{"procName":"dbo.tr_dinhmuc_son3_update","body":"CREATE   PROCEDURE [dbo].[TR_DINHMUC_SON3_UPDATE]
(
	@id uniqueidentifier,
	@masp nvarchar(200),
	@stt int,
	@buoc nvarchar(200),
	@mact nvarchar(50),
	@tenct nvarchar(max),
	@soluong float,
	@matson nvarchar(50),
	@t_sort int,
	@ngaytao datetime,
	@nguoitao nvarchar(50),
	@ngaysua datetime,
	@nguoisua nvarchar(50),
	@makhuvuc nvarchar(50) = NULL,
	@macongdoan nvarchar(50) = NULL,
	@stt_buoc nvarchar(5) = NULL,
	@donhot nvarchar(200) = NULL,
	@thoigiankho nvarchar(200) = NULL,
	@cachthuchien nvarchar(max) = NULL,
	@tonghonhop float = null,
	@tinhtrang_sudung nvarchar(1) = NULL,
	@tinhtrang_uv nvarchar(1) = NULL
)
AS
BEGIN
	SELECT @makhuvuc = department FROM trtb_m_op WHERE c_op = @macongdoan
	IF @makhuvuc IS NULL
		SET @makhuvuc = 'SON'

	UPDATE tr_dinhmuc_son3
	SET
		masp = @masp,
		stt = @stt,
		buoc = @buoc,
		mact = LTRIM(RTRIM(@mact)),
		tenct = @tenct,
		soluong = @soluong,
		matson = @matson,
		t_sort = @t_sort,
		ngaysua = @ngaysua,
		nguoisua = @nguoisua,
		makhuvuc = @makhuvuc,
		macongdoan = @macongdoan,
		stt_buoc = @stt_buoc,
		donhot = @donhot,
		thoigiankho = @thoigiankho,
		cachthuchien = @cachthuchien,
		tonghonhop = @tonghonhop,
		tinhtrang_sudung = @tinhtrang_sudung,
		tinhtrang_uv = @tinhtrang_uv
	WHERE id = @id
